#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int f[N][20],f2[N][20],dis[N],a[N],n,k,maxx,minn;
bool cmp(int x,int y)
{
    return x>y;
}
void fun(int l,int r)
{
    int k=log2(r-l+1);
    maxx=max(f[l][k],f[r-(1<<k)+1][k]);
    minn=min(f2[l][k],f2[r-(1<<k)+1][k]);
}
void prepare()
{
    memset(f,-0x3f,sizeof(f));
    memset(f2,0x3f,sizeof(f2));
    for(int i=1;i<=n;i++)
    {
        f2[i][0]=a[i],f[i][0]=a[i];
    }
    for(int j=1;j<=log2(n);j++)
    {
        for(int i=1;i+(1<<j)-1<=n;i++)
        {
            f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
            f2[i][j]=min(f2[i][j-1],f2[i+(1<<(j-1))][j-1]);
        }
    }
}
int check(int len)
{
    int cnt=0;
    for(int i=1;i+len-1<=n;i++)
    {
        fun(i,i+len-1);
        dis[++cnt]=maxx-minn;
    }
    if(cnt<k) return -1;
	sort(dis+1,dis+cnt+1,cmp);
	return dis[k];
}
void print(int pre){
	int l=1,r=n,ans=0x3f3f3f3f;
	while(l<=r)
    {
		int mid=(l+r)>>1,now=check(mid);
		if(now==-1)	r=mid-1;
		else if(now<pre) l=mid+1;
		else if(now==pre) ans=min(ans,mid),r=mid-1;
	}
	cout<<pre<<" "<<ans<<'\n';
} 
int main()
{
    int t;
    cin>>t;
    while(t--)
    {
        cin>>n>>k;
        for(int i=1;i<=n;i++) cin>>a[i];
        prepare();
        print(check(n-k+1));
    }
    return 0;
}
